import{_ as e,o as t,c as s,ae as n}from"./chunks/framework.y3HA5S76.js";const u=JSON.parse('{"title":"アカウント管理 — /np:account","description":"","frontmatter":{},"headers":[],"relativePath":"guide/accounts.md","filePath":"guide/accounts.md"}'),i={name:"guide/accounts.md"};function p(o,a,c,d,l,h){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="アカウント管理-—-np-account" tabindex="-1">アカウント管理 — <code>/np:account</code> <a class="header-anchor" href="#アカウント管理-—-np-account" aria-label="Permalink to &quot;アカウント管理 — \`/np:account\`&quot;">​</a></h1><p>note-pilotは<strong>noteアカウントを持っていない人も、持っている人も</strong>同じ環境で管理できます。記事を事前に書き溜めてからアカウントを開設する運用にも対応しています。</p><h2 id="アカウントのステータス" tabindex="-1">アカウントのステータス <a class="header-anchor" href="#アカウントのステータス" aria-label="Permalink to &quot;アカウントのステータス&quot;">​</a></h2><p>各アカウントには3つのステータスがあります。</p><table tabindex="0"><thead><tr><th>status</th><th>意味</th><th>記事作成</th><th>校閲</th><th>自動投稿</th></tr></thead><tbody><tr><td><code>preparing</code></td><td>noteアカウント未作成。記事を準備中</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td><code>active</code></td><td>noteアカウントあり。通常運用中</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><code>paused</code></td><td>一時停止中</td><td>✅（確認後）</td><td>✅</td><td>✅（確認後）</td></tr></tbody></table><p><code>preparing</code> 状態でも記事の作成・校閲は通常通り行えます。noteアカウントがないため自己紹介embedは省略されますが、アカウント開設後にステータスを <code>active</code> に変更するだけで、それまでに書いた記事をそのまま投稿できます。</p><h2 id="アカウント一覧を確認する" tabindex="-1">アカウント一覧を確認する <a class="header-anchor" href="#アカウント一覧を確認する" aria-label="Permalink to &quot;アカウント一覧を確認する&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>アカウント一覧を見せて</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/np:account list</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>アカウントを管理したい</span></span></code></pre></div><p>表示例:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[1] travel-note — Travel Note（active）記事35本</span></span>
<span class="line"><span>[2] cooking-log — Cooking Log（active）記事12本</span></span>
<span class="line"><span>[3] new-account — New Account（preparing）記事0本</span></span></code></pre></div><h2 id="新しいアカウントを追加する" tabindex="-1">新しいアカウントを追加する <a class="header-anchor" href="#新しいアカウントを追加する" aria-label="Permalink to &quot;新しいアカウントを追加する&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>アカウントを追加して</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/np:account add</span></span></code></pre></div><p>対話形式で以下を確認します。</p><ol><li>アカウント名（表示名）</li><li>スラッグ（ファイル名に使う英数字識別子）</li><li><strong>noteアカウントを持っているか？</strong><ul><li><strong>持っていない</strong> → <code>status: preparing</code> で作成。note URL は後で設定できます</li><li><strong>持っている</strong> → note URL と自己紹介記事URLを入力して <code>status: active</code> で作成</li></ul></li><li>扱うテーマ</li><li>やらないこと（禁止テーマ）</li></ol><h2 id="noteアカウントを開設したら-preparing-→-active" tabindex="-1">noteアカウントを開設したら（preparing → active） <a class="header-anchor" href="#noteアカウントを開設したら-preparing-→-active" aria-label="Permalink to &quot;noteアカウントを開設したら（preparing → active）&quot;">​</a></h2><p>noteアカウントを取得したら、ステータスを <code>active</code> に切り替えます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>アカウントのステータスを変えて</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/np:account status</span></span></code></pre></div><p>変更時に note URL と自己紹介記事URLの入力を求められます。設定後、それまでに書き溜めた記事は <code>/np:post</code> で投稿できるようになります。</p><h2 id="一時停止・再開する" tabindex="-1">一時停止・再開する <a class="header-anchor" href="#一時停止・再開する" aria-label="Permalink to &quot;一時停止・再開する&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/np:account status</span></span></code></pre></div><p><code>active</code> → <code>paused</code> に変更すると、一時停止の理由を記録できます。 <code>paused</code> → <code>active</code> に変更すると、再開日が自動で記録されます。</p><h2 id="複数アカウントを切り替える" tabindex="-1">複数アカウントを切り替える <a class="header-anchor" href="#複数アカウントを切り替える" aria-label="Permalink to &quot;複数アカウントを切り替える&quot;">​</a></h2><p>複数のアカウント設定ファイルがある場合、記事作成・投稿の際にどのアカウントを使うか選択できます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>アカウントを切り替えて</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/np:account switch</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cooking-logアカウントで記事を書いて</span></span></code></pre></div><h2 id="アカウント設定ファイルの場所" tabindex="-1">アカウント設定ファイルの場所 <a class="header-anchor" href="#アカウント設定ファイルの場所" aria-label="Permalink to &quot;アカウント設定ファイルの場所&quot;">​</a></h2><p>各アカウントは <code>accounts/{slug}.md</code> として管理されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>note-pilot/</span></span>
<span class="line"><span>└── accounts/</span></span>
<span class="line"><span>    ├── account-template.md   ← テンプレート（削除しないでください）</span></span>
<span class="line"><span>    ├── travel-note.md        ← アカウント1</span></span>
<span class="line"><span>    ├── cooking-log.md        ← アカウント2</span></span>
<span class="line"><span>    └── new-account.md        ← アカウント3（preparing）</span></span></code></pre></div>`,33)])])}const g=e(i,[["render",p]]);export{u as __pageData,g as default};
